    display: flex;
    align-items: center;
    flex: 0 0 100%;
    flex-wrap: wrap;
    gap: 0.3rem;
    row-gap: 0.4rem;
    padding-bottom: 0.25rem;
    padding-right: 7rem;
    box-sizing: border-box;
    border-bottom: 0.5px solid var(--border-card);
    margin-bottom: 0.1rem;
}

