    .postcards-parent-container {
        position: relative;
        top: 0;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-top: 0.5rem;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 220px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
        box-sizing: border-box;
    }
    .content-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        user-select: none;
        gap: 0.3rem;
    }
    .feed-title{
        font-size: 0.92rem;
        line-height: 1.3;
    }
    .feed-text-content {
        padding: 0;
        margin: 0;
