        font-size: 0.6rem;
        white-space: nowrap;
    }
    .card-icons-container .user-info-child-container .user-info-avatar{
        width: 20px;
        height: 20px;
    }

    /* Row 2: Action icons — guaranteed visible */
    .icon-container{
        display: flex !important;
        align-items: center;
        flex-shrink: 1;
        min-width: 0;
        min-height: 24px;
        visibility: visible;
    }

    /* Base icon button styles (covers like, comment, bookmark) */
    .icon-container .like-button,
    .icon-container .comment-button,
    .icon-container .bookmark-button{
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.3rem;
        border-radius: 50%;
        transition: background-color 0.2s ease;
    }

    .svg-like{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-comment{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-bookmark{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    #card-icons{
        display: flex;
        align-items: center;
        padding: 0.3rem;
        gap: 0.15rem;
    }
    #card-icons-view{
        display: flex;
        align-items: center;
    }
    #card-icons-view svg{
        width: 22px;
        height: 22px;
    }
    .icon-container p{
        font-family: var(--font-ui);
        font-size: 0.68rem !important;
        white-space: nowrap;
        margin: 0 !important;
        padding: 0 !important;
    }

    /* Reading time pill — absolute top-right, inline with author */
    .reading-time-container{
        position: absolute;
        top: 0.55rem;
        right: 2.5rem;
        display: flex !important;
        visibility: visible;
        margin-left: 0;
        padding: 0.2rem 0.6rem;
        flex-shrink: 0;
        min-width: fit-content;
    }
    .reading-time-text{
        font-size: 0.58rem;
        white-space: nowrap;
    }

    .user-post-settings{
        flex-shrink: 0;
        color: var(--text-heading);
    }
    .user-post-settings svg{
        width: 20px;
        height: 20px;
    }
    .setting-modal{
        right: 0;
        bottom: 25px;
        width: 180px;
        height: 80px;
        font-size: 0.75rem;
    }
    .toolbar {
        display: flex;
        justify-content: center;
        height: 100%;
        width: 100%;
    }
    .toolbar-bttns {
        display: flex;
        width: 16px;
        height: 16px;
        justify-content: center;
        align-items: center;
        padding: 0.5rem;
        border-radius: 10px;
        cursor: pointer;
        transition: ease-in-out 0.1s;
        user-select: none;
    }
    .editor-save-bttn {
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.2rem 0.8rem;
        font-size: 0.8rem;
        border-radius: 15px;
        margin-right: 1rem;
        background-color: rgb(255, 255, 255);
        color: rgb(4, 20, 29);
        font-weight: 600;
        cursor: pointer;
        border: hidden;
    }

